Here's the complete implementation of the functions using the Hexi library:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream >> packet.packet_id;

    // Read username with length prefix
    stream >> hexi::prefixed(packet.username);

    // Read score count and then the scores vector using read_container
    uint32_t score_count;
    stream >> score_count;
    packet.scores.resize(score_count);
    stream >> hexi::read_container(packet.scores);

    // Read metadata as null-terminated string for zero-copy
    std::string_view metadata_view;
    stream >> hexi::cstr(metadata_view);
    packet.metadata = metadata_view; // Convert to std::string (copies the data)

    // Skip any remaining padding bytes by advancing to the end
    adaptor.advance_read(adaptor.size() - adaptor.read_position());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for zero-copy view of packet_id (first 4 bytes)
    auto packet_id_span = stream.span<const uint32_t>(1);
    info.packet_id = packet_id_span[0];

    // Read username using prefixed adaptor to get string_view (zero-copy)
    stream >> hexi::prefixed(info.username);

    // Skip scores vector: read count, then skip the data
    uint32_t score_count;
    stream >> score_count;

    // Skip the scores data by creating a span but not using it
    auto scores_span = stream.span<const uint32_t>(score_count);
    // The span is created but not used, effectively skipping the data

    return info;
}
```

Key points about the implementation:

1. **`deserialize_packet`**:
   - Uses `hexi::prefixed` to read the username with length prefix
   - Uses `hexi::read_container` to read the scores vector after reading the count
   - Uses `hexi::cstr` to read the metadata as a null-terminated string view, then converts to `std::string`
   - Skips remaining padding by advancing the read position to the end

2. **`extract_packet_info`**:
   - Uses `stream.span()` to get a zero-copy view of the packet_id
   - Uses `hexi::prefixed` to get a `std::string_view` of the username (zero-copy)
   - Reads the score count but skips the actual scores data by creating a span that isn't used

Both functions leverage Hexi's zero-copy capabilities where appropriate, particularly for the extraction function which is designed to be efficient by avoiding unnecessary data copying.

