std::vector<uint8_t> create_message_buffer(uint16_t msg_type, uint32_t body_len, const std::vector<uint8_t>& body, uint32_t footer) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << msg_type << body_len;
    stream.put(body.data(), body.size());
    stream << footer;

    return buffer;
}

TEST(MessageHeader, ReadAndSkip) {
    std::vector<uint8_t> body = {1, 2, 3, 4, 5, 6, 7, 8};
