    MessageHeader header = read_header_and_skip_body(buffer);

    EXPECT_EQ(100, header.message_type);
    EXPECT_EQ(body.size(), header.body_length);
    EXPECT_EQ(9999, header.footer);
}

TEST(MessageHeader, SkipLargeBody) {
    std::vector<uint8_t> body(1000, 0xFF);
    auto buffer = create_message_buffer(300, body.size(), body, 5678);

    MessageHeader header = read_header_and_skip_body(buffer);

    EXPECT_EQ(300, header.message_type);
    EXPECT_EQ(1000, header.body_length);
    EXPECT_EQ(5678, header.footer);
}

