    EXPECT_EQ(1, header.version);
    EXPECT_EQ(0x42, header.flags);
    EXPECT_EQ(12345, header.packet_id);
}

TEST(PacketHeader, ReadDifferentValues) {
    auto buffer = create_header_buffer(2, 0xFF, 65535);

    PacketHeader header = read_packet_header(buffer);

    EXPECT_EQ(2, header.version);
    EXPECT_EQ(0xFF, header.flags);
    EXPECT_EQ(65535, header.packet_id);
}

TEST(MessageRead, ReadWithView) {
    auto buffer = create_message_buffer("Hello World");

    std::string_view message = read_message_until_delimiter(buffer);

    EXPECT_EQ("Hello World", message);
}

TEST(MessageRead, ReadEmptyMessage) {
    auto buffer = create_message_buffer("");

    std::string_view message = read_message_until_delimiter(buffer);

    EXPECT_TRUE(message.empty());
}

