```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create a read-only buffer adaptor from the source buffer
    std::span<const uint8_t> source_span(source_buffer);
    hexi::buffer_adaptor adaptor(source_span);

    // Create a binary stream for reading
    hexi::binary_stream stream(adaptor);

    // Read the specified number of bytes
    std::vector<uint8_t> result(bytes_to_read);
    stream.read(result.data(), bytes_to_read);

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create a read-write buffer adaptor from the destination buffer
    std::span<uint8_t> dest_span(dest_buffer);
    hexi::buffer_adaptor adaptor(dest_span);

    // Create a binary stream for writing
    hexi::binary_stream stream(adaptor);

    // Write the source data to the destination buffer
    stream.write(source_data.data(), source_data.size());
}
```

However, based on the code fragments showing error handling with `no_throw`, it might be better to add proper error handling. Here's a more robust version:

```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>
#include <stdexcept>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Check if we have enough data to read
    if (bytes_to_read > source_buffer.size()) {
        throw std::out_of_range("Requested more bytes than available in source buffer");
    }

    // Create a read-only buffer adaptor from the source buffer
    std::span<const uint8_t> source_span(source_buffer);
    hexi::buffer_adaptor adaptor(source_span);

    // Create a binary stream for reading with error handling
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Read the specified number of bytes
    std::vector<uint8_t> result(bytes_to_read);
    stream.read(result.data(), bytes_to_read);

    // Check if read was successful
    if (!stream) {
        throw std::runtime_error("Failed to read from buffer");
    }

    return result;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Ensure destination buffer has enough capacity
    dest_buffer.resize(source_data.size());

    // Create a read-write buffer adaptor from the destination buffer
    std::span<uint8_t> dest_span(dest_buffer);
    hexi::buffer_adaptor adaptor(dest_span);

    // Create a binary stream for writing with error handling
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Write the source data to the destination buffer
    stream.write(source_data.data(), source_data.size());

    // Check if write was successful
    if (!stream) {
        throw std::runtime_error("Failed to write to buffer");
    }
}
```

