    std::vector<uint8_t> buffer = {1, 2, 3};

    BufferInfo info = check_buffer_space(buffer);

    EXPECT_EQ(3, info.readable_size);
    EXPECT_GE(info.free_space, 0);
}

TEST(BufferAdaptor, CheckEmptyBuffer) {
    std::vector<uint8_t> buffer;

    BufferInfo info = check_buffer_space(buffer);

    EXPECT_EQ(0, info.readable_size);
}

