bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer adaptor for the vector
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream with error handling (no exceptions)
    hexi::binary_stream stream(adaptor, hexi::no_throw);

    // Check available space before writing
    // We need space for: header (uint32_t) + vector size + all vector items
    std::size_t required_space = sizeof(header) + sizeof(uint32_t) + (items.size() * sizeof(uint32_t));

    if (adaptor.capacity() - adaptor.size() < required_space) {
        return false; // Insufficient space
