    // Write the header
    stream.put(header);

    // Write the vector using write_container (equivalent to put_container)
    stream.put_container(items);

    // Check if write was successful by examining stream state
    if (stream) {
        return true; // Write successful
    } else {
        return false; // Write failed due to stream error
    }
}
