```cpp
#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream from the adaptor
    hexi::binary_stream stream(adaptor);

    // Get the read pointer and check available data
    const auto* read_ptr = adaptor.read_pointer();
    const auto available = adaptor.available_read();

    // Ensure we have enough data for the header
    constexpr size_t header_size = sizeof(PacketHeader);
    if (available < header_size) {
        throw std::runtime_error("Insufficient data for header");
    }

    // Get a zero-copy view of the header using binary_stream's read method
    auto header_view = stream.read(header_size);

    // Create PacketHeader from the zero-copy view
    PacketHeader header;
    std::memcpy(&header, header_view.data(), header_size);

    return header;
}
```

