#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <string_view>

struct MessagePacket {
    uint32_t header;
    std::string_view message;
};

MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);

    // Read header using buffer_adaptor's read()
    uint32_t header = 0;
    adaptor.read(&header, sizeof(uint32_t));

    // Read message using binary_stream's view()
    hexi::binary_stream stream(adaptor);
    std::string_view message = stream.view();

    MessagePacket packet;
    packet.header = header;
    packet.message = message;

    return packet;
}

