#include <hexi/allocators/block_allocator.h>
#include <cstdint>

struct test_block {
    std::byte data[1024];
};

template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    hexi::block_allocator<test_block, element_count> allocator;

    // Allocate blocks - internally uses pop() to get from free list
    auto* block1 = allocator.allocate();
    auto* block2 = allocator.allocate();

    // Deallocate blocks - internally uses push() to return to free list
    allocator.deallocate(block1);
    allocator.deallocate(block2);

    // Subsequent allocations reuse the freed blocks
    auto* block3 = allocator.allocate();
    auto* block4 = allocator.allocate();

    allocator.deallocate(block3);
    allocator.deallocate(block4);
}

