Looking at the code fragments and the Hexi library usage patterns, I can implement the requested functions using `hexi::file_buffer`. Here's the complete implementation:

```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    // Create a file buffer for reading
    hexi::file_buffer buffer(file_path);

    // Get the actual readable size (don't read beyond file size)
    size_t actual_read_size = std::min(bytes_to_read, buffer.size());

    // Create result vector and read data
    std::vector<uint8_t> data(actual_read_size);
    if (actual_read_size > 0) {
        buffer.read(data.data(), actual_read_size);
    }

    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    // Create a file buffer for reading
    hexi::file_buffer buffer(file_path);

    // Get the actual preview size (don't read beyond file size)
    size_t actual_preview_size = std::min(bytes_to_preview, buffer.size());

    // Create result vector and preview data
    std::vector<uint8_t> data(actual_preview_size);
    if (actual_preview_size > 0) {
        // Preview reads without advancing the read pointer
        // This is typically done by reading and then restoring position
        auto current_pos = buffer.tell(); // Get current position
        buffer.read(data.data(), actual_preview_size);
        buffer.seek(current_pos); // Restore original position
    }

    return data;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    // Create a file buffer for writing (this will create/truncate the file)
    hexi::file_buffer buffer(file_path, hexi::file_buffer::write);

    // Write the data to file
    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    // Create a file buffer and get its size
    hexi::file_buffer buffer(file_path);
    return buffer.size();
}
```

