// Include the implementation
#include "implementation.hpp"

// Helper function to create a test file
void create_test_file(const std::filesystem::path& file_path, size_t size) {
    std::ofstream file(file_path, std::ios::binary);
    std::vector<uint8_t> data(size, 0xAA);
    file.write(reinterpret_cast<const char*>(data.data()), data.size());
    file.close();
}

TEST(FileBuffer, GetFileReadableSize) {
    std::filesystem::path test_file = "test_size.bin";
    size_t expected_size = 100;
    create_test_file(test_file, expected_size);

    size_t file_size = get_file_readable_size(test_file);

    EXPECT_EQ(expected_size, file_size);

    std::filesystem::remove(test_file);
}

TEST(FileBuffer, GetEmptyFileSize) {
    std::filesystem::path test_file = "test_empty.bin";
    create_test_file(test_file, 0);

