```cpp
#include <hexi/static_buffer.h>

template<size_t buffer_size = 1024>
struct BufferInfo {
    size_t capacity;
    size_t current_size;
    size_t free_space;
};

BufferInfo<> get_buffer_info(const hexi::static_buffer<std::byte, 1024>& buffer) {
    BufferInfo<> info;

    // Total capacity is fixed by the template parameter
    info.capacity = 1024;

    // Get the current read and write offsets from the buffer
    // For a circular buffer, current size is write_offset - read_offset
    // but we need to handle wrap-around
    size_t read_offset = buffer.read_offset();
    size_t write_offset = buffer.write_offset();

    if (write_offset >= read_offset) {
        // Normal case: write pointer is ahead of read pointer
        info.current_size = write_offset - read_offset;
    } else {
        // Wrap-around case: write pointer has wrapped around
        info.current_size = info.capacity - read_offset + write_offset;
    }

    // Available free space is capacity minus current size
    info.free_space = info.capacity - info.current_size;

    return info;
}
```

The key points:
- Capacity is fixed at compile time (1024 bytes)
- Current size is calculated based on the relationship between read and write pointers
- Free space is simply capacity minus current size
- The implementation handles the circular buffer wrap-around case

