#include <hexi/pmc/binary_stream_writer.h>
#include <hexi/pmc/binary_stream_reader.h>
#include <hexi/pmc/buffer_adaptor.h>
#include <vector>
#include <cstdint>

struct UserData {
    uint32_t user_id;
    std::string name;

    void serialise(auto& stream) {
        stream << user_id << name;
    }
};

void serialize_object(hexi::pmc::binary_stream_writer& writer, const UserData& data) {
    // Create a temporary buffer to hold the serialized data
    std::vector<std::byte> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Create a stream that can write to the buffer
    hexi::pmc::binary_stream_writer temp_writer(adaptor);

    // Serialize the data using the object's serialise method
    // We need to remove const since serialise might modify the stream position
    UserData& non_const_data = const_cast<UserData&>(data);
    non_const_data.serialise(temp_writer);

    // Write the size of the serialized data first
    writer << static_cast<uint32_t>(buffer.size());

    // Then write the actual serialized data
    writer.write_bytes(buffer.data(), buffer.size());
}

void deserialize_object(hexi::pmc::binary_stream_reader& reader, UserData& data) {
    // Read the size of the serialized data first
    uint32_t data_size;
    reader >> data_size;

    // Read the serialized data into a buffer
    std::vector<std::byte> buffer(data_size);
    reader.read_bytes(buffer.data(), data_size);

    // Create a buffer adaptor and reader for the serialized data
    hexi::pmc::buffer_adaptor adaptor(buffer);
    hexi::pmc::binary_stream_reader data_reader(adaptor);

    // Deserialize the data using the object's serialise method
    data.serialise(data_reader);
}
