TEST(BufferAdaptor, ReadHeaderAndSkipBody) {
    std::vector<std::byte> storage(1000);
    hexi::pmc::buffer_adaptor adaptor(storage, hexi::init_empty);

    MessageHeader header;
    header.message_type = 123;
    header.body_length = 8;

    uint8_t body[8] = {1, 2, 3, 4, 5, 6, 7, 8};

    adaptor.write(&header.message_type, sizeof(header.message_type));
    adaptor.write(&header.body_length, sizeof(header.body_length));
    adaptor.write(body, sizeof(body));

    uint32_t footer = 999;
