void update_header_at_position(hexi::pmc::buffer_adaptor<std::vector<std::byte>>& buffer, uint32_t header_value) {
    // Save current write position by seeking with offset 0 from current position
    // This effectively "saves" the current position without moving
    buffer.write_seek(hexi::buffer_seek::current, 0);

    // Write header placeholder (initial value, will be updated later)
    uint32_t placeholder = 0;
