```cpp
#include <hexi/shared.h>
#include <cstring>
#include <cstddef>

using namespace hexi::detail;

bool check_regions_overlap(const void* src, std::size_t src_len, const void* dst, std::size_t dst_len) {
    if (!src || !dst || src_len == 0 || dst_len == 0) {
        return false;
    }

    const auto* src_start = static_cast<const char*>(src);
    const auto* src_end = src_start + src_len;
    const auto* dst_start = static_cast<const char*>(dst);
    const auto* dst_end = dst_start + dst_len;

    // Check if regions overlap by comparing their start and end addresses
    return (src_start < dst_end) && (dst_start < src_end);
}

bool safe_memory_copy(void* destination, const void* source, std::size_t length) {
    if (!destination || !source || length == 0) {
        return false;
    }

    // Check for overlap using the helper function
    if (check_regions_overlap(source, length, destination, length)) {
        return false; // Overlap detected, unsafe to copy
    }

    // Safe to copy - use memcpy
    std::memcpy(destination, source, length);
    return true;
}
```

This implementation:

1. **`check_regions_overlap`**:
   - Handles edge cases (null pointers, zero length)
   - Converts pointers to `char*` for byte arithmetic
   - Uses standard overlap detection logic: regions overlap if one starts before the other ends and vice versa

2. **`safe_memory_copy`**:
   - Validates input parameters
   - Uses `check_regions_overlap` to detect unsafe copying scenarios
   - Only performs `memcpy` when it's safe to do so
   - Returns `true` on success, `false` on failure (overlap or invalid input)

The logic ensures that memory operations are safe by preventing overlapping copies that could lead to data corruption.

