    CustomBuffer buffer;

    std::vector<uint8_t> data1 = {1, 2};
    std::vector<uint8_t> data2 = {3, 4, 5};

    buffer.add_data(data1.data(), data1.size());
    EXPECT_EQ(2, buffer.size());

    buffer.add_data(data2.data(), data2.size());
    EXPECT_EQ(5, buffer.size());
    EXPECT_FALSE(buffer.empty());
}

