class CustomBuffer : public hexi::pmc::buffer_base {
    std::vector<std::byte> data_;

public:
    // Required virtual methods from buffer_base
    std::size_t size() const override {
        return data_.size();
    }

    bool empty() const override {
        return data_.empty();
    }

    // Virtual methods from buffer_read (inherited through buffer_base)
    void read(void* destination, std::size_t length) override {
        if (length > data_.size()) {
            HEXI_THROW(hexi::exception("Read beyond buffer size"));
        }
        std::memcpy(destination, data_.data(), length);
        data_.erase(data_.begin(), data_.begin() + length);
    }

    void copy(void* destination, std::size_t length) const override {
        if (length > data_.size()) {
            HEXI_THROW(hexi::exception("Copy beyond buffer size"));
        }
        std::memcpy(destination, data_.data(), length);
    }

    void skip(std::size_t length) override {
        if (length > data_.size()) {
            HEXI_THROW(hexi::exception("Skip beyond buffer size"));
        }
        data_.erase(data_.begin(), data_.begin() + length);
    }

    const std::byte& operator[](const std::size_t index) const override {
        if (index >= data_.size()) {
            HEXI_THROW(hexi::exception("Index out of bounds"));
        }
        return data_[index];
    }

    std::size_t find_first_of(std::byte val) const override {
        for (std::size_t i = 0; i < data_.size(); ++i) {
            if (data_[i] == val) {
                return i;
            }
        }
        return npos; // static_cast<std::size_t>(-1)
    }

    // Virtual methods from buffer_write (inherited through buffer_base)
    void write(const void* source, std::size_t length) override {
        const std::byte* bytes = static_cast<const std::byte*>(source);
        data_.insert(data_.end(), bytes, bytes + length);
    }

    void reserve(std::size_t length) override {
        data_.reserve(data_.size() + length);
    }

    bool can_write_seek() const override {
        return false; // This buffer doesn't support write seeking
    }

    void write_seek(hexi::pmc::buffer_seek direction, std::size_t offset) override {
        HEXI_THROW(hexi::exception("Write seek not supported on CustomBuffer"));
