```cpp
#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to write into
    std::vector<uint8_t> buffer;

    // Create a write adaptor for the buffer
    hexi::pmc::buffer_write_adaptor adaptor(buffer);

    std::size_t total_written = 0;

    // Write each chunk
    for (const auto& chunk : chunks) {
        // Check available space before each write
        std::size_t available_space = adaptor.free();

        // If there's not enough space, we might need to handle this,
        // but for this implementation we'll assume the buffer grows automatically
        // or we'll write what we can
        std::size_t bytes_to_write = std::min(chunk.size(), available_space);

        if (bytes_to_write > 0) {
            adaptor.write(chunk.data(), bytes_to_write);
            total_written += bytes_to_write;
        }

        // Update buffer state after write
        adaptor.advance_write(bytes_to_write);
    }

    return total_written;
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a read adaptor for the buffer
    hexi::pmc::buffer_read_adaptor adaptor(const_cast<std::vector<uint8_t>&>(buffer));

    std::vector<uint8_t> result;

    // Read until buffer is empty
    while (adaptor.size() > 0) {
        // Check remaining data
        std::size_t remaining = adaptor.size();
        std::size_t bytes_to_read = std::min(chunk_size, remaining);

        if (bytes_to_read > 0) {
            // Read partial data
            std::vector<uint8_t> chunk(bytes_to_read);
            adaptor.read(chunk.data(), bytes_to_read);

            // Append to result
            result.insert(result.end(), chunk.begin(), chunk.end());

            // Advance read position
            adaptor.advance_read(bytes_to_read);
        }
    }

    return result;
}
```

Key points about this implementation:

1. **write_multiple_chunks**:
   - Uses `buffer_write_adaptor` to write data in chunks
   - Checks `free()` before each write to determine available space
   - Uses `advance_write()` to update the buffer state after each write
   - Returns the total number of bytes written

2. **read_partial_data**:
   - Uses `buffer_read_adaptor` to read data partially
   - Checks `size()` after each read to determine remaining data
   - Reads in chunks of the specified size until the buffer is empty
   - Uses `advance_read()` to update the read position

The implementation follows the Hexi library patterns seen in the test fragments, particularly the usage of `advance_write()`, `advance_read()`, `size()`, and `free()` methods on the buffer adaptors.

