```cpp
#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& stream) const {
        // Write sensor_id directly (no endian conversion needed for serialization)
        stream(sensor_id);

        // Convert and write each temperature value from native to little-endian
        for (const auto& temp : temperatures) {
            float little_endian_temp = hexi::conditional_reverse(temp, std::endian::native, std::endian::little);
            stream.write(&little_endian_temp, sizeof(float));
        }

        // Convert and write pressure from native to little-endian
        double little_endian_pressure = hexi::conditional_reverse(pressure, std::endian::native, std::endian::little);
        stream.write(&little_endian_pressure, sizeof(double));
    }

    void serialise(auto& stream) {
        // Read sensor_id directly
        stream(sensor_id);

        // Determine the number of temperature values based on remaining data
        // We need to calculate how many floats can fit before the double pressure
        size_t remaining_bytes = stream.remaining();
        size_t num_temperatures = (remaining_bytes - sizeof(double)) / sizeof(float);

        // Read and convert each temperature value
        temperatures.resize(num_temperatures);
        for (auto& temp : temperatures) {
            stream.read(&temp, sizeof(float));
            hexi::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        stream.read(&pressure, sizeof(double));
        hexi::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Serialize the data structure
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    MeasurementData data;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Deserialize the data structure
    stream.deserialise(data);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    SensorInfo info;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use view to extract null-terminated sensor name string
    info.sensor_name = stream.view('\0');

    // Use enforce_read_bounds to check if there's enough data for sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(&info.sensor_id, sizeof(uint32_t));

    // Skip the remaining data
    stream.skip(stream.remaining());

    return info;
}
